-- Migration 032: Lise (9-12) kazanımları seed — MEB Türkiye Yüzyılı Maarif Modeli 2025
-- 17 JSON dosyasından üretildi, toplam 1614 kazanım.
-- Mevcut lise kazanımları temizlendi, yeni müfredatla değiştirildi.

-- 1. Eski lise kazanımlarını temizle
DELETE FROM kazanimlar WHERE okul_tipi = 'lise';

-- 2. Yeni lise kazanımlarını ekle
ON CONFLICT (kod) DO UPDATE SET
  brans_id  = EXCLUDED.brans_id,
  sinif     = EXCLUDED.sinif,
  unite_no  = EXCLUDED.unite_no,
  unite_ad  = EXCLUDED.unite_ad,
  ad        = EXCLUDED.ad,
  ders      = EXCLUDED.ders,
  okul_tipi = EXCLUDED.okul_tipi,
  ders_turu = EXCLUDED.ders_turu;